```class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        int res = 0, i = 0;
        while (i < n) {
            int j = i;
            while (j < n && text[j] == text[n - 1 - j + i]) j++;
            res = max(res, j - i + 1);
            i = j;
        }
        return res;
    }
};```
